<script>(()=>{const csrf=<?=json_encode($csrf)?>,$=id=>document.getElementById(id),status=$('status'),preview=$('preview'),generate=$('generate'),publish=$('publishBtn');let image='';function message(text,error=false){status.textContent=text;status.classList.toggle('error',error)}function title(){return $('title').value.trim()||$('idea').value.trim().split(/[,.]/)[0].slice(0,70)||'Generated Stencil'}function show(data){image=data;preview.innerHTML='';const img=new Image();img.src=data;img.alt=title()+' generated tattoo stencil';preview.appendChild(img);publish.disabled=false}generate.onclick=async()=>{const idea=$('idea').value.trim();if(idea.length<8){message('Describe the stencil concept in a little more detail.',true);return}generate.disabled=true;publish.disabled=true;message('Creating high-resolution transfer-ready artwork…');try{const r=await fetch('api/generate-stencil.php',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-Token':csrf},body:JSON.stringify({idea,style:$('style').value,placement:$('placement').value})});const d=await r.json();if(!r.ok||!d.ok)throw new Error(d.error||'Generation failed.');show(d.image);message('Stencil generated. Review it, add a title, then publish when approved.')}catch(e){message(e.message,true)}finally{generate.disabled=false}};$('clear').onclick=()=>{image='';publish.disabled=true;preview.innerHTML='<div class="empty"><b>✦</b><h2>Generated stencil preview</h2><p>Your high-resolution black-and-white artwork will appear here for review before publishing.</p></div>';message('')};publish.onclick=async()=>{if(!image)return;publish.disabled=true;message('Building the library pack and publishing…');try{const svg='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1024 1536"><image width="1024" height="1536" href="generated-stencil-of-the-day.png"/></svg>';const r=await fetch('publish-tattoo.php',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-Token':csrf},body:JSON.stringify({title:title(),motif:$('idea').value,style:$('style').value,placement:$('placement').value,collection:$('collection').value,svg,png:image,seed:'openai-gpt-image-2'})});const d=await r.json();if(!r.ok||!d.ok)throw new Error(d.error||'Publishing failed.');message('Published successfully. Beyond Tattoo now uses this stencil.');publish.textContent='Published ✓'}catch(e){message(e.message,true);publish.disabled=false}}})();</script></body></html>
